import test from "node:test";
import assert from "node:assert/strict";
import os from "node:os";
import path from "node:path";
import { promises as fs } from "node:fs";

import { loadPilotFeatureCatalog } from "./pilotFeatureCatalogService.js";

const baseEntry = {
  id: "web.portfolio",
  surface: "web",
  title: "Portfolio overview",
  shortSummary: "Shows the user's portfolio health and holdings.",
  detailedExplanation: "The portfolio page summarizes holdings, account grouping, active analysis jobs, and attention items derived from current verdicts.",
  happyPath: ["Authenticated user opens /portfolio", "Portfolio API data renders holdings and health summary"],
  edgeCases: ["Empty portfolio shows an empty state", "Fetch failure renders a retryable error state"],
  errorHandling: ["Portfolio query failures render ErrorState instead of stale or blank data"],
  evidencePaths: ["frontend/src/pages/Portfolio.tsx", "frontend/src/App.tsx"],
  pilotRecommendation: "pilot",
};

async function writeCatalog(dir: string, fileName: string, value: unknown): Promise<void> {
  await fs.mkdir(dir, { recursive: true });
  await fs.writeFile(path.join(dir, fileName), JSON.stringify(value, null, 2), "utf-8");
}

async function makeCatalogDir(): Promise<string> {
  return fs.mkdtemp(path.join(os.tmpdir(), "pilot-feature-catalog-"));
}

test("pilot feature catalog loads valid entries and sorts by surface, title, and id", async () => {
  const catalogDir = await makeCatalogDir();
  await writeCatalog(catalogDir, "pilot-core.json", {
    entries: [
      { ...baseEntry, id: "web.zeta", title: "Zeta", surface: "web" },
      { ...baseEntry, id: "telegram.daily-brief", title: "Daily brief delivery", surface: "telegram", evidencePaths: ["backend/src/routes/telegram.ts"] },
      { ...baseEntry, id: "web.alpha-b", title: "Alpha", surface: "web" },
      { ...baseEntry, id: "web.alpha-a", title: "Alpha", surface: "web" },
    ],
  });

  const entries = await loadPilotFeatureCatalog({ catalogDir });

  assert.deepEqual(entries.map((entry) => entry.id), [
    "telegram.daily-brief",
    "web.alpha-a",
    "web.alpha-b",
    "web.zeta",
  ]);
  assert.equal(entries[0]?.errorHandling.length, 1);
});

test("default pilot feature catalog includes substantive Web, Telegram, and admin coverage", async () => {
  const entries = await loadPilotFeatureCatalog();
  const ids = new Set(entries.map((entry) => entry.id));

  assert.ok(entries.length >= 8);
  assert.ok(entries.some((entry) => entry.surface === "web"));
  assert.ok(entries.some((entry) => entry.surface === "telegram"));
  assert.ok(entries.some((entry) => entry.surface === "admin"));
  assert.ok(ids.has("web.onboarding-portfolio"));
  assert.ok(ids.has("telegram.daily-brief-chat"));
  assert.ok(entries.every((entry) => entry.shortSummary.length > 20));
  assert.ok(entries.every((entry) => entry.errorHandling.length > 0));
});

test("pilot feature catalog rejects duplicate feature ids across files", async () => {
  const catalogDir = await makeCatalogDir();
  await writeCatalog(catalogDir, "a.json", { entries: [baseEntry] });
  await writeCatalog(catalogDir, "b.json", { entries: [{ ...baseEntry, title: "Duplicate title" }] });

  await assert.rejects(
    () => loadPilotFeatureCatalog({ catalogDir }),
    /Duplicate pilot feature id web\.portfolio/
  );
});

test("pilot feature catalog rejects schema violations with file path and reason", async () => {
  const catalogDir = await makeCatalogDir();
  const invalid = { ...baseEntry } as Record<string, unknown>;
  delete invalid["errorHandling"];
  await writeCatalog(catalogDir, "invalid.json", { entries: [invalid] });

  await assert.rejects(
    () => loadPilotFeatureCatalog({ catalogDir }),
    /invalid\.json.*entries\.0\.errorHandling.*Required/s
  );
});

test("pilot feature catalog rejects malformed JSON with file path and parse reason", async () => {
  const catalogDir = await makeCatalogDir();
  await fs.mkdir(catalogDir, { recursive: true });
  await fs.writeFile(path.join(catalogDir, "broken.json"), "{ not json", "utf-8");

  await assert.rejects(
    () => loadPilotFeatureCatalog({ catalogDir }),
    /broken\.json.*Malformed JSON/s
  );
});

test("pilot feature catalog rejects unsafe evidence paths", async () => {
  const catalogDir = await makeCatalogDir();
  await writeCatalog(catalogDir, "unsafe.json", {
    entries: [
      { ...baseEntry, id: "unsafe.users", evidencePaths: ["users/alice/private.json"] },
      { ...baseEntry, id: "unsafe.env", evidencePaths: ["backend/.env"] },
      { ...baseEntry, id: "unsafe.runtime", evidencePaths: ["data/reports/batch.json"] },
    ],
  });

  await assert.rejects(
    () => loadPilotFeatureCatalog({ catalogDir }),
    /Unsafe evidence path.*users\/alice\/private\.json/s
  );
});

import test from "node:test";
import assert from "node:assert/strict";

import type { PilotFeatureCatalogEntry } from "../schemas/pilotFeature.js";
import {
  PilotFeatureReviewServiceError,
  listPilotFeaturesWithReviews,
  upsertPilotFeatureReview,
  pilotFeatureReviewServiceInternals,
} from "./pilotFeatureReviewService.js";

const catalog: PilotFeatureCatalogEntry[] = [
  {
    id: "web.portfolio",
    surface: "web",
    title: "Portfolio overview",
    shortSummary: "Shows portfolio status.",
    detailedExplanation: "Shows portfolio holdings, health, and active analysis status for the pilot.",
    happyPath: ["User opens portfolio"],
    edgeCases: ["Empty portfolio renders an empty state"],
    errorHandling: ["API failure renders retryable error state"],
    evidencePaths: ["frontend/src/pages/Portfolio.tsx"],
    pilotRecommendation: "pilot",
  },
  {
    id: "telegram.daily-brief",
    surface: "telegram",
    title: "Daily brief delivery",
    shortSummary: "Sends daily summaries.",
    detailedExplanation: "Sends pilot daily brief summaries through the Telegram channel.",
    happyPath: ["Scheduler triggers daily brief"],
    edgeCases: ["Telegram chat is not linked"],
    errorHandling: ["Delivery failure is logged and retried by job lifecycle"],
    evidencePaths: ["backend/src/routes/telegram.ts"],
    pilotRecommendation: "pilot",
  },
];

interface QueryCall {
  sql: string;
  params: unknown[];
}

function makeDataSource(rowsByCall: unknown[][] = []) {
  const calls: QueryCall[] = [];
  return {
    calls,
    ds: {
      async query<T = unknown>(sql: string, params: unknown[]): Promise<T> {
        calls.push({ sql, params });
        return (rowsByCall.shift() ?? []) as T;
      },
    },
  };
}

function configuredDeps(ds: { query<T = unknown>(sql: string, params: unknown[]): Promise<T> }) {
  return {
    catalogLoader: async () => catalog,
    databaseConfigured: () => true,
    dataSourceProvider: async () => ds,
  };
}

test("pilot feature review service composes catalog entries with default and persisted review state", async () => {
  const { ds, calls } = makeDataSource([
    [
      {
        feature_id: "telegram.daily-brief",
        status: "beta",
        admin_comment: "Watch first pilot cohort before marking ready.",
        incorrect_description: false,
        updated_at: new Date("2026-01-02T03:04:05.000Z"),
        updated_by: "owner",
      },
    ],
  ]);

  const result = await listPilotFeaturesWithReviews(configuredDeps(ds));

  assert.equal(calls.length, 1);
  assert.match(calls[0]!.sql, /WHERE feature_id = ANY\(\$1::text\[\]\)/);
  assert.deepEqual(calls[0]!.params, [["web.portfolio", "telegram.daily-brief"]]);
  assert.equal(result[0]!.review.status, "unreviewed");
  assert.equal(result[0]!.review.updatedAt, null);
  assert.equal(result[1]!.review.status, "beta");
  assert.equal(result[1]!.review.adminComment, "Watch first pilot cohort before marking ready.");
  assert.equal(result[1]!.review.updatedAt, "2026-01-02T03:04:05.000Z");
});

test("pilot feature review service upserts a known feature review", async () => {
  const updatedAt = new Date("2026-02-03T04:05:06.000Z");
  const { ds, calls } = makeDataSource([
    [
      {
        feature_id: "web.portfolio",
        status: "ready",
        admin_comment: "Good enough for pilot.",
        incorrect_description: true,
        updated_at: updatedAt,
        updated_by: "owner",
      },
    ],
  ]);

  const result = await upsertPilotFeatureReview(
    {
      featureId: " web.portfolio ",
      status: "ready",
      adminComment: "Good enough for pilot.",
      incorrectDescription: true,
      updatedBy: " owner ",
    },
    configuredDeps(ds)
  );

  assert.equal(calls.length, 1);
  assert.match(calls[0]!.sql, /ON CONFLICT \(feature_id\)/);
  assert.deepEqual(calls[0]!.params, [
    "web.portfolio",
    "ready",
    "Good enough for pilot.",
    true,
    "owner",
  ]);
  assert.equal(result.id, "web.portfolio");
  assert.deepEqual(result.review, {
    status: "ready",
    adminComment: "Good enough for pilot.",
    incorrectDescription: true,
    updatedAt: "2026-02-03T04:05:06.000Z",
    updatedBy: "owner",
  });
});

test("pilot feature review service rejects invalid status and oversized comments before writing", async () => {
  const { ds, calls } = makeDataSource();

  await assert.rejects(
    () => upsertPilotFeatureReview(
      {
        featureId: "web.portfolio",
        status: "launched",
        updatedBy: "owner",
      },
      configuredDeps(ds)
    ),
    (error: unknown) => error instanceof PilotFeatureReviewServiceError && error.code === "INVALID_REVIEW_INPUT"
  );

  await assert.rejects(
    () => upsertPilotFeatureReview(
      {
        featureId: "web.portfolio",
        status: "ready",
        adminComment: "x".repeat(pilotFeatureReviewServiceInternals.MAX_ADMIN_COMMENT_LENGTH + 1),
        updatedBy: "owner",
      },
      configuredDeps(ds)
    ),
    (error: unknown) => error instanceof PilotFeatureReviewServiceError && error.code === "INVALID_REVIEW_INPUT"
  );

  assert.equal(calls.length, 0);
});

test("pilot feature review service refuses unknown catalog ids before writing", async () => {
  const { ds, calls } = makeDataSource();

  await assert.rejects(
    () => upsertPilotFeatureReview(
      {
        featureId: "web.missing",
        status: "ready",
        updatedBy: "owner",
      },
      configuredDeps(ds)
    ),
    (error: unknown) => error instanceof PilotFeatureReviewServiceError && error.code === "UNKNOWN_FEATURE_ID"
  );

  assert.equal(calls.length, 0);
});

test("pilot feature review service exposes unavailable database and catalog load failures as typed errors", async () => {
  const { ds, calls } = makeDataSource();

  await assert.rejects(
    () => listPilotFeaturesWithReviews({
      catalogLoader: async () => catalog,
      databaseConfigured: () => false,
      dataSourceProvider: async () => ds,
    }),
    (error: unknown) => error instanceof PilotFeatureReviewServiceError && error.code === "DATABASE_UNAVAILABLE"
  );
  assert.equal(calls.length, 0);

  await assert.rejects(
    () => listPilotFeaturesWithReviews({
      catalogLoader: async () => { throw new Error("boom"); },
      databaseConfigured: () => true,
      dataSourceProvider: async () => ds,
    }),
    (error: unknown) => error instanceof PilotFeatureReviewServiceError && error.code === "CATALOG_LOAD_FAILED"
  );
});

import test from "node:test";
import assert from "node:assert/strict";
import type { PilotFeatureWithReview } from "../services/pilotFeatureReviewService.js";
import { PilotFeatureReviewServiceError } from "../services/pilotFeatureReviewService.js";

process.env["ADMIN_KEY"] = "test-admin-key";
process.env["APP_DATABASE_URL"] = "postgres://admin-pilot-feature-test";

const baseFeature = {
  id: "web.dashboard",
  surface: "web" as const,
  title: "Web dashboard",
  shortSummary: "Browse portfolio health.",
  detailedExplanation: "Shows current portfolio health to the pilot user.",
  happyPath: ["Open dashboard"],
  edgeCases: ["Empty portfolio"],
  errorHandling: ["Show a recoverable empty state"],
  evidencePaths: ["backend/src/routes/admin.ts"],
  pilotRecommendation: "pilot" as const,
};

function feature(
  id: string,
  surface: PilotFeatureWithReview["surface"],
  status: PilotFeatureWithReview["review"]["status"],
  title = id
): PilotFeatureWithReview {
  return {
    ...baseFeature,
    id,
    surface,
    title,
    review: {
      status,
      adminComment: null,
      incorrectDescription: false,
      updatedAt: null,
      updatedBy: null,
    },
  };
}

async function invokeAdminRouterJson(options: {
  method: "GET" | "PATCH";
  url: string;
  query?: Record<string, unknown>;
  body?: unknown;
  adminKey?: string;
}): Promise<{ statusCode: number; body: unknown }> {
  const adminModule = await import("./admin.js");
  const adminRouter = adminModule.default as unknown as {
    handle: (req: object, res: object, next: (error?: unknown) => void) => void;
  };

  return await new Promise((resolve, reject) => {
    const req = {
      method: options.method,
      url: options.url,
      originalUrl: options.url,
      headers: { "x-admin-key": options.adminKey ?? "test-admin-key" },
      query: options.query ?? {},
      body: options.body,
    };
    const res = {
      statusCode: 200,
      status(code: number) {
        this.statusCode = code;
        return this;
      },
      json(body: unknown) {
        resolve({ statusCode: this.statusCode, body });
        return this;
      },
    };

    adminRouter.handle(req, res, (error?: unknown) => {
      if (error) reject(error);
      else reject(new Error(`Route fell through without response for ${options.method} ${options.url}`));
    });
  });
}

test("admin pilot features GET /pilot-features composes review state, filters, and paginates", async () => {
  const { setPilotFeatureAdminRouteDepsForTest } = await import("./admin.js");
  setPilotFeatureAdminRouteDepsForTest({
    databaseConfigured: () => true,
    listPilotFeaturesWithReviews: async () => [
      feature("web.dashboard", "web", "ready", "Dashboard"),
      feature("telegram.alerts", "telegram", "ready", "Telegram alerts"),
      feature("web.chat", "web", "ready", "Chat"),
      feature("web.settings", "web", "hidden", "Settings"),
    ],
    upsertPilotFeatureReview: async () => feature("unused", "web", "ready"),
  });

  const result = await invokeAdminRouterJson({
    method: "GET",
    url: "/pilot-features",
    query: { surface: "web", status: "ready", limit: "1", offset: "1" },
  });

  assert.equal(result.statusCode, 200);
  assert.deepEqual(result.body, {
    items: [feature("web.chat", "web", "ready", "Chat")],
    total: 2,
    limit: 1,
    offset: 1,
    databaseAvailable: true,
  });
});

test("admin pilot features PATCH /pilot-features/:featureId/review updates state and subsequent list reads it", async () => {
  const { setPilotFeatureAdminRouteDepsForTest } = await import("./admin.js");
  const store = new Map<string, PilotFeatureWithReview>([
    ["web.dashboard", feature("web.dashboard", "web", "unreviewed", "Dashboard")],
  ]);
  setPilotFeatureAdminRouteDepsForTest({
    databaseConfigured: () => true,
    listPilotFeaturesWithReviews: async () => Array.from(store.values()),
    upsertPilotFeatureReview: async (input) => {
      const current = store.get(input.featureId);
      if (!current) {
        throw new PilotFeatureReviewServiceError("UNKNOWN_FEATURE_ID", "unknown", { featureId: input.featureId });
      }
      const updated: PilotFeatureWithReview = {
        ...current,
        review: {
          status: input.status as PilotFeatureWithReview["review"]["status"],
          adminComment: input.adminComment ?? null,
          incorrectDescription: input.incorrectDescription ?? false,
          updatedAt: "2026-05-09T00:00:00.000Z",
          updatedBy: input.updatedBy,
        },
      };
      store.set(input.featureId, updated);
      return updated;
    },
  });

  const patch = await invokeAdminRouterJson({
    method: "PATCH",
    url: "/pilot-features/web.dashboard/review",
    body: {
      status: "needs_fix",
      adminComment: "Description omits the empty portfolio case.",
      incorrectDescription: true,
      updatedBy: "route-test",
    },
  });

  assert.equal(patch.statusCode, 200);
  assert.equal((patch.body as { feature: PilotFeatureWithReview }).feature.review.status, "needs_fix");

  const list = await invokeAdminRouterJson({ method: "GET", url: "/pilot-features" });
  const listed = (list.body as { items: PilotFeatureWithReview[] }).items[0];
  assert.equal(listed?.review.status, "needs_fix");
  assert.equal(listed?.review.adminComment, "Description omits the empty portfolio case.");
  assert.equal(listed?.review.incorrectDescription, true);
  assert.equal(listed?.review.updatedBy, "route-test");
});

test("admin pilot features PATCH /pilot-features/:featureId/review preserves omitted review fields", async () => {
  const { setPilotFeatureAdminRouteDepsForTest } = await import("./admin.js");
  const existing = feature("web.dashboard", "web", "beta", "Dashboard");
  existing.review.adminComment = "Keep this comment.";
  existing.review.incorrectDescription = true;
  setPilotFeatureAdminRouteDepsForTest({
    databaseConfigured: () => true,
    listPilotFeaturesWithReviews: async () => [existing],
    upsertPilotFeatureReview: async (input) => ({
      ...existing,
      review: {
        status: input.status as PilotFeatureWithReview["review"]["status"],
        adminComment: input.adminComment ?? null,
        incorrectDescription: input.incorrectDescription ?? false,
        updatedAt: "2026-05-09T00:00:00.000Z",
        updatedBy: input.updatedBy,
      },
    }),
  });

  const result = await invokeAdminRouterJson({
    method: "PATCH",
    url: "/pilot-features/web.dashboard/review",
    body: { status: "ready", updatedBy: "route-test" },
  });

  assert.equal(result.statusCode, 200);
  const updated = (result.body as { feature: PilotFeatureWithReview }).feature;
  assert.equal(updated.review.status, "ready");
  assert.equal(updated.review.adminComment, "Keep this comment.");
  assert.equal(updated.review.incorrectDescription, true);
});

test("admin pilot features GET /pilot-features rejects invalid filters", async () => {
  const { setPilotFeatureAdminRouteDepsForTest } = await import("./admin.js");
  setPilotFeatureAdminRouteDepsForTest({
    databaseConfigured: () => true,
    listPilotFeaturesWithReviews: async () => [feature("web.dashboard", "web", "ready")],
    upsertPilotFeatureReview: async () => feature("unused", "web", "ready"),
  });

  const result = await invokeAdminRouterJson({
    method: "GET",
    url: "/pilot-features",
    query: { status: "published" },
  });

  assert.equal(result.statusCode, 400);
  assert.equal((result.body as { error?: string }).error, "invalid_pilot_feature_filter");
});

test("admin pilot features PATCH /pilot-features/:featureId/review rejects invalid status and comment", async () => {
  const { setPilotFeatureAdminRouteDepsForTest } = await import("./admin.js");
  setPilotFeatureAdminRouteDepsForTest({
    databaseConfigured: () => true,
    listPilotFeaturesWithReviews: async () => [feature("web.dashboard", "web", "ready")],
    upsertPilotFeatureReview: async () => feature("unused", "web", "ready"),
  });

  const invalidStatus = await invokeAdminRouterJson({
    method: "PATCH",
    url: "/pilot-features/web.dashboard/review",
    body: { status: "published", updatedBy: "route-test" },
  });
  assert.equal(invalidStatus.statusCode, 422);
  assert.equal((invalidStatus.body as { error?: string }).error, "invalid_pilot_feature_review");

  const invalidComment = await invokeAdminRouterJson({
    method: "PATCH",
    url: "/pilot-features/web.dashboard/review",
    body: { adminComment: "x".repeat(2_001), updatedBy: "route-test" },
  });
  assert.equal(invalidComment.statusCode, 422);
  assert.equal((invalidComment.body as { error?: string }).error, "invalid_pilot_feature_review");
});

test("admin pilot features PATCH /pilot-features/:featureId/review returns 404 and does not write unknown feature ids", async () => {
  const { setPilotFeatureAdminRouteDepsForTest } = await import("./admin.js");
  let wrote = false;
  setPilotFeatureAdminRouteDepsForTest({
    databaseConfigured: () => true,
    listPilotFeaturesWithReviews: async () => [feature("web.dashboard", "web", "ready")],
    upsertPilotFeatureReview: async () => {
      wrote = true;
      return feature("unknown", "web", "ready");
    },
  });

  const result = await invokeAdminRouterJson({
    method: "PATCH",
    url: "/pilot-features/not-in-catalog/review",
    body: { status: "ready", updatedBy: "route-test" },
  });

  assert.equal(result.statusCode, 404);
  assert.equal((result.body as { error?: string }).error, "pilot_feature_not_found");
  assert.equal(wrote, false);
});

test("admin pilot features GET /pilot-features returns 503 instead of partial catalog when database is unavailable", async () => {
  const { setPilotFeatureAdminRouteDepsForTest } = await import("./admin.js");
  setPilotFeatureAdminRouteDepsForTest({
    databaseConfigured: () => false,
    listPilotFeaturesWithReviews: async () => {
      throw new PilotFeatureReviewServiceError("DATABASE_UNAVAILABLE", "db unavailable");
    },
    upsertPilotFeatureReview: async () => feature("unused", "web", "ready"),
  });

  const result = await invokeAdminRouterJson({ method: "GET", url: "/pilot-features" });

  assert.equal(result.statusCode, 503);
  assert.deepEqual(result.body, {
    error: "application_database_unavailable",
    databaseAvailable: false,
  });
});

import { z } from "zod";

export const PilotFeatureSurfaceSchema = z.enum(["admin", "operator", "telegram", "web"]);

export const PilotFeatureReviewStatusSchema = z.enum([
  "unreviewed",
  "needs_fix",
  "beta",
  "hidden",
  "ready",
]);

export const PilotFeatureRecommendationSchema = z.enum([
  "pilot",
  "beta",
  "defer",
  "hide",
]);

const NonEmptyStringArraySchema = z.array(z.string().trim().min(1)).min(1);

export const PilotFeatureCatalogEntrySchema = z.object({
  id: z.string().trim().min(1).regex(/^[a-z0-9]+(?:[._-][a-z0-9]+)*$/),
  surface: PilotFeatureSurfaceSchema,
  title: z.string().trim().min(1),
  shortSummary: z.string().trim().min(1),
  detailedExplanation: z.string().trim().min(1),
  happyPath: NonEmptyStringArraySchema,
  edgeCases: NonEmptyStringArraySchema,
  errorHandling: NonEmptyStringArraySchema,
  evidencePaths: NonEmptyStringArraySchema,
  pilotRecommendation: PilotFeatureRecommendationSchema,
}).strict();

export const PilotFeatureCatalogFileSchema = z.object({
  entries: z.array(PilotFeatureCatalogEntrySchema).min(1),
}).strict();

export type PilotFeatureSurface = z.infer<typeof PilotFeatureSurfaceSchema>;
export type PilotFeatureReviewStatus = z.infer<typeof PilotFeatureReviewStatusSchema>;
export type PilotFeatureRecommendation = z.infer<typeof PilotFeatureRecommendationSchema>;
export type PilotFeatureCatalogEntry = z.infer<typeof PilotFeatureCatalogEntrySchema>;
export type PilotFeatureCatalogFile = z.infer<typeof PilotFeatureCatalogFileSchema>;

import { getApplicationDataSource, isApplicationDatabaseConfigured } from "../db/applicationDataSource.js";
import type { PilotFeatureReviewEntity } from "../db/entities/PilotFeatureReviewEntity.js";
import {
  PilotFeatureReviewStatusSchema,
  type PilotFeatureCatalogEntry,
  type PilotFeatureReviewStatus,
} from "../schemas/pilotFeature.js";
import {
  PilotFeatureCatalogError,
  loadPilotFeatureCatalog,
} from "./pilotFeatureCatalogService.js";
import { logger } from "./logger.js";

const MAX_ADMIN_COMMENT_LENGTH = 2_000;
const MAX_UPDATED_BY_LENGTH = 128;

export type PilotFeatureReviewServiceErrorCode =
  | "DATABASE_UNAVAILABLE"
  | "CATALOG_LOAD_FAILED"
  | "INVALID_REVIEW_INPUT"
  | "UNKNOWN_FEATURE_ID";

export class PilotFeatureReviewServiceError extends Error {
  constructor(
    public readonly code: PilotFeatureReviewServiceErrorCode,
    message: string,
    public readonly details: Record<string, string> = {}
  ) {
    super(message);
    this.name = "PilotFeatureReviewServiceError";
  }
}

export interface PilotFeatureReviewState {
  status: PilotFeatureReviewStatus;
  adminComment: string | null;
  incorrectDescription: boolean;
  updatedAt: string | null;
  updatedBy: string | null;
}

export interface PilotFeatureWithReview extends PilotFeatureCatalogEntry {
  review: PilotFeatureReviewState;
}

export interface UpsertPilotFeatureReviewInput {
  featureId: string;
  status: PilotFeatureReviewStatus | string;
  adminComment?: string | null;
  incorrectDescription?: boolean;
  updatedBy: string;
}

interface PilotFeatureReviewDataSource {
  query<T = unknown>(sql: string, parameters?: unknown[]): Promise<T>;
}

interface PilotFeatureReviewRow {
  feature_id: string;
  status: PilotFeatureReviewStatus;
  admin_comment: string | null;
  incorrect_description: boolean;
  updated_at: Date | string;
  updated_by: string;
}

interface PilotFeatureReviewServiceDeps {
  catalogLoader?: () => Promise<PilotFeatureCatalogEntry[]>;
  databaseConfigured?: () => boolean;
  dataSourceProvider?: () => Promise<PilotFeatureReviewDataSource>;
}

const SELECT_COLUMNS =
  "feature_id, status, admin_comment, incorrect_description, updated_at, updated_by";

function defaultReview(): PilotFeatureReviewState {
  return {
    status: "unreviewed",
    adminComment: null,
    incorrectDescription: false,
    updatedAt: null,
    updatedBy: null,
  };
}

function toIso(value: Date | string): string {
  return (value instanceof Date ? value : new Date(value)).toISOString();
}

function fromRow(row: PilotFeatureReviewRow): PilotFeatureReviewState {
  return {
    status: row.status,
    adminComment: row.admin_comment,
    incorrectDescription: row.incorrect_description,
    updatedAt: toIso(row.updated_at),
    updatedBy: row.updated_by,
  };
}

function toEntity(row: PilotFeatureReviewRow): PilotFeatureReviewEntity {
  return {
    featureId: row.feature_id,
    status: row.status,
    adminComment: row.admin_comment,
    incorrectDescription: row.incorrect_description,
    updatedAt: row.updated_at instanceof Date ? row.updated_at : new Date(row.updated_at),
    updatedBy: row.updated_by,
  };
}

function serviceDeps(deps: PilotFeatureReviewServiceDeps): Required<PilotFeatureReviewServiceDeps> {
  return {
    catalogLoader: deps.catalogLoader ?? loadPilotFeatureCatalog,
    databaseConfigured: deps.databaseConfigured ?? isApplicationDatabaseConfigured,
    dataSourceProvider: deps.dataSourceProvider ?? getApplicationDataSource,
  };
}

async function loadCatalogForReview(
  catalogLoader: () => Promise<PilotFeatureCatalogEntry[]>
): Promise<PilotFeatureCatalogEntry[]> {
  try {
    return await catalogLoader();
  } catch (error) {
    const reason = error instanceof PilotFeatureCatalogError ? error.message : "catalog load failed";
    logger.warn(`pilot_feature_review_catalog_failed reason=${reason}`);
    throw new PilotFeatureReviewServiceError(
      "CATALOG_LOAD_FAILED",
      "Pilot feature catalog could not be loaded",
      { reason }
    );
  }
}

async function getReviewDataSource(
  deps: Required<PilotFeatureReviewServiceDeps>,
  featureId?: string
): Promise<PilotFeatureReviewDataSource> {
  if (!deps.databaseConfigured()) {
    throw new PilotFeatureReviewServiceError(
      "DATABASE_UNAVAILABLE",
      "Pilot feature review storage is not configured"
    );
  }

  try {
    return await deps.dataSourceProvider();
  } catch (error) {
    const reason = error instanceof Error ? error.message : String(error);
    logger.warn(`pilot_feature_review_db_unavailable feature_id=${featureId ?? "<list>"} reason=${reason}`);
    throw new PilotFeatureReviewServiceError(
      "DATABASE_UNAVAILABLE",
      "Pilot feature review storage is unavailable",
      { reason }
    );
  }
}

function validateReviewInput(input: UpsertPilotFeatureReviewInput): {
  featureId: string;
  status: PilotFeatureReviewStatus;
  adminComment: string | null;
  incorrectDescription: boolean;
  updatedBy: string;
} {
  const featureId = input.featureId.trim();
  if (!featureId) {
    throw new PilotFeatureReviewServiceError("INVALID_REVIEW_INPUT", "featureId is required", {
      field: "featureId",
    });
  }

  const parsedStatus = PilotFeatureReviewStatusSchema.safeParse(input.status);
  if (!parsedStatus.success) {
    throw new PilotFeatureReviewServiceError("INVALID_REVIEW_INPUT", "Invalid pilot feature review status", {
      field: "status",
    });
  }

  const adminComment = input.adminComment === undefined ? null : input.adminComment;
  if (adminComment !== null) {
    if (typeof adminComment !== "string") {
      throw new PilotFeatureReviewServiceError("INVALID_REVIEW_INPUT", "adminComment must be a string or null", {
        field: "adminComment",
      });
    }
    if (adminComment.length > MAX_ADMIN_COMMENT_LENGTH) {
      throw new PilotFeatureReviewServiceError("INVALID_REVIEW_INPUT", "adminComment is too long", {
        field: "adminComment",
        maxLength: String(MAX_ADMIN_COMMENT_LENGTH),
      });
    }
  }

  const updatedBy = input.updatedBy.trim();
  if (!updatedBy || updatedBy.length > MAX_UPDATED_BY_LENGTH) {
    throw new PilotFeatureReviewServiceError("INVALID_REVIEW_INPUT", "updatedBy is required and must be bounded", {
      field: "updatedBy",
      maxLength: String(MAX_UPDATED_BY_LENGTH),
    });
  }

  return {
    featureId,
    status: parsedStatus.data,
    adminComment,
    incorrectDescription: input.incorrectDescription ?? false,
    updatedBy,
  };
}

function findKnownCatalogEntry(
  catalog: PilotFeatureCatalogEntry[],
  featureId: string
): PilotFeatureCatalogEntry {
  const entry = catalog.find((candidate) => candidate.id === featureId);
  if (!entry) {
    throw new PilotFeatureReviewServiceError("UNKNOWN_FEATURE_ID", "Pilot feature id is not in the catalog", {
      featureId,
    });
  }
  return entry;
}

export async function listPilotFeaturesWithReviews(
  deps: PilotFeatureReviewServiceDeps = {}
): Promise<PilotFeatureWithReview[]> {
  const resolvedDeps = serviceDeps(deps);
  const catalog = await loadCatalogForReview(resolvedDeps.catalogLoader);
  const featureIds = catalog.map((entry) => entry.id);
  const ds = await getReviewDataSource(resolvedDeps);

  let rows: PilotFeatureReviewRow[];
  try {
    rows = await ds.query(
      `SELECT ${SELECT_COLUMNS}
         FROM pilot_feature_reviews
        WHERE feature_id = ANY($1::text[])`,
      [featureIds]
    ) as PilotFeatureReviewRow[];
  } catch (error) {
    const reason = error instanceof Error ? error.message : String(error);
    logger.warn(`pilot_feature_review_list_failed reason=${reason}`);
    throw new PilotFeatureReviewServiceError(
      "DATABASE_UNAVAILABLE",
      "Pilot feature review storage is unavailable",
      { reason }
    );
  }

  const reviewsByFeatureId = new Map(rows.map((row) => [row.feature_id, fromRow(row)]));
  return catalog.map((entry) => ({
    ...entry,
    review: reviewsByFeatureId.get(entry.id) ?? defaultReview(),
  }));
}

export async function upsertPilotFeatureReview(
  input: UpsertPilotFeatureReviewInput,
  deps: PilotFeatureReviewServiceDeps = {}
): Promise<PilotFeatureWithReview> {
  const validated = validateReviewInput(input);
  const resolvedDeps = serviceDeps(deps);
  const catalog = await loadCatalogForReview(resolvedDeps.catalogLoader);
  const entry = findKnownCatalogEntry(catalog, validated.featureId);
  const ds = await getReviewDataSource(resolvedDeps, validated.featureId);

  let rows: PilotFeatureReviewRow[];
  try {
    rows = await ds.query(
      `INSERT INTO pilot_feature_reviews
         (feature_id, status, admin_comment, incorrect_description, updated_at, updated_by)
       VALUES ($1, $2, $3, $4, NOW(), $5)
       ON CONFLICT (feature_id)
       DO UPDATE SET
         status = EXCLUDED.status,
         admin_comment = EXCLUDED.admin_comment,
         incorrect_description = EXCLUDED.incorrect_description,
         updated_at = NOW(),
         updated_by = EXCLUDED.updated_by
       RETURNING ${SELECT_COLUMNS}`,
      [
        validated.featureId,
        validated.status,
        validated.adminComment,
        validated.incorrectDescription,
        validated.updatedBy,
      ]
    ) as PilotFeatureReviewRow[];
  } catch (error) {
    const reason = error instanceof Error ? error.message : String(error);
    logger.warn(`pilot_feature_review_upsert_failed feature_id=${validated.featureId} reason=${reason}`);
    throw new PilotFeatureReviewServiceError(
      "DATABASE_UNAVAILABLE",
      "Pilot feature review storage is unavailable",
      { reason, featureId: validated.featureId }
    );
  }

  return {
    ...entry,
    review: fromRow(rows[0]!),
  };
}

